function Sidebar({ newObject }) {
    return (
        <aside className="sidebar">
            <button onClick={newObject}>Add object</button>
            <div className="editObj">
                <h2>Edit object</h2>
                <div className="editColor">
                    <div>
             <button className="colEditGreen" />
                    </div>
                </div>
                <div>
                    <div className="objForm" />
                    <p className="objFormName">Circle</p>
                </div>
            </div>
        </aside>
    );
}

export default Sidebar;
